import{_ as n,c as a,a1 as e,o as r}from"./chunks/framework.BDxlaA_J.js";const u=JSON.parse('{"title":"Các công cụ khác cho Recon","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/7-Other-Tools.md","filePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/7-Other-Tools.md"}'),i={name:"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/7-Other-Tools.md"};function o(c,t,h,l,g,s){return r(),a("div",null,t[0]||(t[0]=[e('<h1 id="cac-cong-cu-khac-cho-recon" tabindex="-1">Các công cụ khác cho Recon <a class="header-anchor" href="#cac-cong-cu-khac-cho-recon" aria-label="Permalink to &quot;Các công cụ khác cho Recon&quot;">​</a></h1><p>Sublist3r là công cụ Python được thiết kế để liệt kê subdomain của trang web sử dụng OSINT.</p><p><a href="https://github.com/aboul3la/Sublist3r" target="_blank" rel="noreferrer">https://github.com/aboul3la/Sublist3r</a></p><p>Đăng nhập vào máy Kali và mở terminal</p><p>Gõ lệnh này để cập nhật các gói Kali rolling và cài đặt sublist3r:</p><p><code>sudo apt update &amp;&amp; apt -y install sublist3r</code></p><p>Gõ <code>sublist3r -h</code> để in tổng quan tất cả các tùy chọn có sẵn.</p><blockquote><p>Để tìm kiếm subdomain, gõ: <code>sublist3r -d google.com -t 3 -e bing</code><code>-d</code> = tên miền mục tiêu <code>-t</code> = số lượng thread <code>-e</code> = công cụ tìm kiếm</p></blockquote><p>Bạn cũng có thể tìm subdomain nào có cổng 80 mở, ví dụ trên <code>google.com</code>.</p><p><code>sublist3r -d google.com -p 80 -e bing</code></p><h1 id="web-data-extractor" tabindex="-1">Web Data Extractor <a class="header-anchor" href="#web-data-extractor" aria-label="Permalink to &quot;Web Data Extractor&quot;">​</a></h1><p>Web Data Extractor được sử dụng để trích xuất thông tin liên hệ hoặc dữ liệu của công ty mục tiêu như email, fax, điện thoại qua web để giao tiếp b2b có trách nhiệm.</p><p>Công cụ này chỉ dành cho Windows, rất dễ sử dụng. Nhược điểm: phiên bản dùng thử chỉ xuất 10 dòng báo cáo. <a href="http://www.webextractor.com/" target="_blank" rel="noreferrer">http://www.webextractor.com/</a></p><h1 id="httrack" tabindex="-1">HTTrack <a class="header-anchor" href="#httrack" aria-label="Permalink to &quot;HTTrack&quot;">​</a></h1><p>Web site copier là tiện ích trình duyệt ngoại tuyến tải một trang web về thư mục cục bộ.</p><p>Ứng dụng này có sẵn ở giao diện GUI và CLI.</p><p>Hoạt động trên Linux/OSX/BSD/Unix, Windows và Android. <a href="https://www.httrack.com/" target="_blank" rel="noreferrer">https://www.httrack.com/</a></p><h1 id="truy-vet-email" tabindex="-1">Truy vết Email <a class="header-anchor" href="#truy-vet-email" aria-label="Permalink to &quot;Truy vết Email&quot;">​</a></h1><p>Truy vết email bao gồm phân tích <strong>email header</strong> để khám phá chi tiết về người gửi. Theo dõi email rất hữu ích để xác định công ty và mạng cung cấp dịch vụ cho địa chỉ đó.</p><p><strong>eMailTrackerPro</strong> là công cụ để theo dõi, phát hiện bất thường trong email header. <a href="http://www.emailtrackerpro.com/" target="_blank" rel="noreferrer">http://www.emailtrackerpro.com/</a></p><h1 id="thu-thap-thong-tin-ip-va-ten-mien-su-dung-whois-lookup" tabindex="-1">Thu thập thông tin IP và tên miền sử dụng Whois Lookup <a class="header-anchor" href="#thu-thap-thong-tin-ip-va-ten-mien-su-dung-whois-lookup" aria-label="Permalink to &quot;Thu thập thông tin IP và tên miền sử dụng Whois Lookup&quot;">​</a></h1><p>Whois lookup hiển thị thông tin có sẵn trên hostname, địa chỉ IP hoặc tên miền.</p><ul><li>Cho Windows: <a href="https://smartwhois.en.softonic.com/" target="_blank" rel="noreferrer"><strong>SmartWhois</strong></a></li><li>Kali Linux: <a href="https://www.cyberpratibha.com/blog/using-whois-a-command-for-information-gathering/" target="_blank" rel="noreferrer"><strong>lệnh whois</strong></a></li></ul><h1 id="truy-vet-tuyen-mang-nang-cao-su-dung-path-analyzer-pro" tabindex="-1">Truy vết tuyến mạng nâng cao sử dụng Path Analyzer Pro <a class="header-anchor" href="#truy-vet-tuyen-mang-nang-cao-su-dung-path-analyzer-pro" aria-label="Permalink to &quot;Truy vết tuyến mạng nâng cao sử dụng Path Analyzer Pro&quot;">​</a></h1><p>Path Analyzer Pro cung cấp khả năng truy vết tuyến mạng nâng cao với kiểm thử hiệu suất, DNS, whois và phân giải mạng để điều tra các vấn đề mạng.</p><p>Hoạt động trên Linux/Mac/Windows. Ứng dụng trả phí với phiên bản dùng thử 10 ngày. <a href="https://www.pathanalyzer.com/" target="_blank" rel="noreferrer">https://www.pathanalyzer.com/</a></p><h1 id="fingerprinting-tu-đong-su-dung-foca" tabindex="-1">Fingerprinting tự động sử dụng FOCA <a class="header-anchor" href="#fingerprinting-tu-đong-su-dung-foca" aria-label="Permalink to &quot;Fingerprinting tự động sử dụng FOCA&quot;">​</a></h1><p>Fingerprinting Organizations with Collected Archives (FOCA) là công cụ tiết lộ metadata và dữ liệu bị che giấu. Các kho lưu trữ này có thể nằm trên các trang web, và có thể được tải về và phân tích bằng FOCA. <em>Kho lưu trữ chính thức:</em> <a href="https://github.com/ElevenPaths/FOCA" target="_blank" rel="noreferrer">https://github.com/ElevenPaths/FOCA</a></p><p>Tính năng:</p><ul><li>Trích xuất Metadata</li><li>Phân tích mạng</li><li>DNS Snooping</li><li>Tìm kiếm file phổ biến</li><li>File hấp dẫn</li><li>Tìm kiếm Proxy</li><li>Nhận diện công nghệ</li><li>Fingerprinting</li><li>Rò rỉ</li><li>Tìm kiếm bản sao lưu</li><li>Buộc lỗi</li><li>Tìm kiếm thư mục mở</li></ul>',30)]))}const d=n(i,[["render",o]]);export{u as __pageData,d as default};
